module RefModule(
               input            CLK,
               input            RST, 
               input            UP,
               input            DOWN,
               output reg [3:0] CODE
               );reg [3:0]                    unused_cnt4;
   always @( posedge CLK ) begin
      if ( !RST )
        unused_cnt4 <= 4'b0000;
      else if ( UP ) 
        unused_cnt4 <= unused_cnt4 + 4'b0001;
      else if ( DOWN ) 
        unused_cnt4 <= unused_cnt4 - 4'b0001;
   end


   always @* begin
      CODE = unused_cnt4 ^ (unused_cnt4 >> 1);
   end

endmodule
